SELECT reservation_id AS reservationId, guest_id AS guestId, house_id AS houseId, status, checkin_date AS checkinDate, checkout_date AS checkoutDate, total_price AS totalPrice, created_at AS createdAt, updated_at AS updatedAt FROM reservations WHERE 1=1
AND status = #{status}
AND #{date} BETWEEN checkin_date AND checkout_date
